    } on FormatException catch (e) {
      debugPrint('Invalid link format: ${e.message}');
    }
  }

  void _handleIncomingLinks() {
    _linkSubscription = linkStream.listen(
      (String? link) {
        if (link != null) {
          _processDeepLink(link);
        }
      },
      onError: (err) {
        debugPrint('Error handling incoming link: $err');
      },
    );
  }

  Future<void> _processDeepLink(String link) async {
    try {
      final uri = Uri.parse(link);

      if (!_isValidHost(uri.host)) {
        debugPrint('Invalid host: ${uri.host}');
        _navigateToError('Invalid deep link host');
        return;
      }

      final pathSegments = uri.pathSegments;
      if (pathSegments.isEmpty) {
        _navigateToHome();
        return;
      }

      final route = pathSegments[0];
      if (!_isValidRoute(route)) {
        debugPrint('Invalid route: $route');
        _navigateToError('Invalid deep link route');
        return;
      }

      final params = uri.queryParameters;

      switch (route) {
        case 'profile':
          await _handleProfileRoute(pathSegments, params);
          break;
        case 'payment':
          await _handlePaymentRoute(pathSegments, params);
          break;
        case 'product':
          await _handleProductRoute(pathSegments, params);
          break;
        case 'category':
          await _handleCategoryRoute(pathSegments, params);
          break;
        case 'settings':
          await _handleSettingsRoute(pathSegments, params);
          break;
        case 'home':
          _navigateToHome();
          break;
        default:
          _navigateToError('Unknown route');
      }
    } catch (e) {
      debugPrint('Error processing deep link: $e');
      _navigateToError('Failed to process deep link');
    }
  }

  bool _isValidHost(String host) {
    return _allowedHosts.contains(host.toLowerCase());
