    }

    final tab = params['tab'];
    if (tab != null && !_isValidProfileTab(tab)) {
      _navigateToError('Invalid profile tab');
      return;
    }

    _navigate('/profile', arguments: {
      'userId': userId,
      'tab': tab,
    });
  }

  Future<void> _handlePaymentRoute(
    List<String> pathSegments,
    Map<String, String> params,
  ) async {
    if (pathSegments.length < 2) {
      _navigateToError('Invalid payment route');
      return;
    }

    final action = pathSegments[1];
    if (!_isValidPaymentAction(action)) {
      _navigateToError('Invalid payment action');
      return;
    }

    switch (action) {
      case 'confirm':
        await _handlePaymentConfirm(params);
        break;
      case 'status':
        await _handlePaymentStatus(params);
        break;
      case 'history':
        _navigate('/payment/history');
        break;
      default:
        _navigateToError('Unknown payment action');
    }
  }

  Future<void> _handlePaymentConfirm(Map<String, String> params) async {
    final transactionId = params['transaction_id'];
    final amount = params['amount'];
    final currency = params['currency'];

    if (transactionId == null || !_isValidTransactionId(transactionId)) {
      _navigateToError('Invalid transaction ID');
      return;
    }

    if (amount != null && !_isValidAmount(amount)) {
      _navigateToError('Invalid amount');
      return;
    }

    if (currency != null && !_isValidCurrency(currency)) {
      _navigateToError('Invalid currency');
      return;
    }

    _navigate('/payment/confirm', arguments: {
      'transactionId': transactionId,
      'amount': amount,
      'currency': currency,
    });
  }

  Future<void> _handlePaymentStatus(Map<String, String> params) async {
    final orderId = params['order_id'];
    if (orderId == null || !_isValidOrderId(orderId)) {
      _navigateToError('Invalid order ID');
      return;
    }

    _navigate('/payment/status', arguments: {
      'orderId': orderId,
    });
