      return;
    }

    final categoryId = pathSegments[1];
    if (!_isValidCategoryId(categoryId)) {
      _navigateToError('Invalid category ID');
      return;
    }

    final sort = params['sort'];
    if (sort != null && !_isValidSortOption(sort)) {
      _navigateToError('Invalid sort option');
