  Future<void> _handleSettingsRoute(
    List<String> pathSegments,
    Map<String, String> params,
  ) async {
    String? section;
    if (pathSegments.length > 1) {
      section = pathSegments[1];
      if (!_isValidSettingsSection(section)) {
