  bool _isValidUserId(String userId) {
    return RegExp(r'^\d+$').hasMatch(userId) && userId.length <= 20;
  }

  bool _isValidProfileTab(String tab) {
    const validTabs = ['posts', 'about', 'photos', 'videos'];
    return validTabs.contains(tab.toLowerCase());
  }

  bool _isValidPaymentAction(String action) {
    const validActions = ['confirm', 'status', 'history'];
    return validActions.contains(action.toLowerCase());
  }

  bool _isValidTransactionId(String transactionId) {
    return RegExp(r'^[a-zA-Z0-9_-]{10,50}$').hasMatch(transactionId);
  }

  bool _isValidAmount(String amount) {
    final parsed = double.tryParse(amount);
    return parsed != null && parsed > 0 && parsed < 1000000;
  }

  bool _isValidCurrency(String currency) {
    const validCurrencies = ['USD', 'EUR', 'GBP', 'JPY', 'AUD', 'CAD'];
    return validCurrencies.contains(currency.toUpperCase());
  }

  bool _isValidOrderId(String orderId) {
    return RegExp(r'^[a-zA-Z0-9_-]{5,30}$').hasMatch(orderId);
  }

  bool _isValidProductId(String productId) {
    return RegExp(r'^[a-zA-Z0-9_-]{1,50}$').hasMatch(productId);
  }

  bool _isValidVariant(String variant) {
    return RegExp(r'^[a-zA-Z0-9_-]{1,30}$').hasMatch(variant);
  }

  bool _isValidCategoryId(String categoryId) {
    return RegExp(r'^[a-zA-Z0-9_-]{1,50}$').hasMatch(categoryId);
  }

  bool _isValidSortOption(String sort) {
    const validOptions = ['price_asc', 'price_desc', 'name', 'newest', 'popular'];
    return validOptions.contains(sort.toLowerCase());
  }

  bool _isValidSettingsSection(String section) {
    const validSections = ['account', 'privacy', 'notifications', 'security'];
    return validSections.contains(section.toLowerCase());
  }

  void _navigate(String route, {Map<String, dynamic>? arguments}) {
    navigatorKey.currentState?.pushNamed(route, arguments: arguments);
  }

  void _navigateToHome() {
    navigatorKey.currentState?.pushNamedAndRemoveUntil('/', (route) => false);
  }

  void _navigateToError(String message) {
