class MyApp extends StatelessWidget {
  final DeepLinkHandler deepLinkHandler = DeepLinkHandler();

  MyApp({Key? key}) : super(key: key);

  @override
  Widget build(BuildContext context) {
    return MaterialApp(
      title: 'Deep Link Demo',
      navigatorKey: deepLinkHandler.navigatorKey,
      initialRoute: '/',
      onGenerateRoute: (settings) {
        final args = settings.arguments as Map<String, dynamic>?;

        switch (settings.name) {
          case '/':
            return MaterialPageRoute(builder: (_) => HomeScreen());
          case '/profile':
            return MaterialPageRoute(
              builder: (_) => ProfileScreen(
                userId: args?['userId'] ?? '',
                tab: args?['tab'],
              ),
            );
          case '/payment/confirm':
            return MaterialPageRoute(
              builder: (_) => PaymentConfirmScreen(
                transactionId: args?['transactionId'] ?? '',
                amount: args?['amount'],
                currency: args?['currency'],
              ),
            );
          case '/payment/status':
            return MaterialPageRoute(
              builder: (_) => PaymentStatusScreen(
                orderId: args?['orderId'] ?? '',
              ),
            );
          case '/payment/history':
            return MaterialPageRoute(
              builder: (_) => Scaffold(
                appBar: AppBar(title: Text('Payment History')),
                body: Center(child: Text('Payment History')),
              ),
            );
          case '/product':
            return MaterialPageRoute(
              builder: (_) => ProductScreen(
                productId: args?['productId'] ?? '',
                variant: args?['variant'],
              ),
            );
          case '/category':
            return MaterialPageRoute(
              builder: (_) => CategoryScreen(
                categoryId: args?['categoryId'] ?? '',
                sort: args?['sort'],
              ),
            );
          case '/settings':
            return MaterialPageRoute(
              builder: (_) => SettingsScreen(
                section: args?['section'],
              ),
            );
          case '/error':
            return MaterialPageRoute(
              builder: (_) => ErrorScreen(
                message: args?['message'] ?? 'Unknown error',
              ),
            );
          default:
            return MaterialPageRoute(
              builder: (_) => ErrorScreen(message: 'Route not found'),
            );
        }
      },
    );
  }
}

void main() {
  WidgetsFlutterBinding.ensureInitialized();
  final deepLinkHandler = DeepLinkHandler();
  deepLinkHandler.initialize();
  runApp(MyApp());
}